import{_ as r,o as n,c as i,ag as a}from"./chunks/framework.CMWvBNEy.js";const u=JSON.parse('{"title":"Agentic Harness: Workflow Overview","description":"","frontmatter":{},"headers":[],"relativePath":"guide/agentic-usage.md","filePath":"guide/agentic-usage.md"}'),t={name:"guide/agentic-usage.md"};function o(s,e,l,c,g,p){return n(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="agentic-harness-workflow-overview" tabindex="-1">Agentic Harness: Workflow Overview <a class="header-anchor" href="#agentic-harness-workflow-overview" aria-label="Permalink to &quot;Agentic Harness: Workflow Overview&quot;">​</a></h1><p>Mocking GUI goes beyond being a simple library — it is an <strong>Agentic Harness</strong> system where a team of specialized AI agents builds and maintains an optimized mocking ecosystem for your environment.</p><p>The harness operates across two professional tracks: core library development and solution engineering. All agents work with deep expertise in Mocking GUI&#39;s core architecture and browser/frontend engineering.</p><h2 id="🏗️-1-core-development-track" tabindex="-1">🏗️ 1. Core Development Track <a class="header-anchor" href="#🏗️-1-core-development-track" aria-label="Permalink to &quot;🏗️ 1. Core Development Track&quot;">​</a></h2><p>An internal engineering pipeline responsible for the completeness and architecture of the Mocking GUI library itself.</p><h3 id="primary-workflow-harness-dev-pipeline" tabindex="-1">Primary Workflow: <code>/harness-dev-pipeline</code> <a class="header-anchor" href="#primary-workflow-harness-dev-pipeline" aria-label="Permalink to &quot;Primary Workflow: `/harness-dev-pipeline`&quot;">​</a></h3><ol><li><strong>Scenario-Driven Design</strong>: Define how a feature behaves in code before implementation, and validate architectural consistency upfront.</li><li><strong>High-Precision Engineering</strong>: Implement stable, extensible core logic using TypeScript&#39;s strict type system.</li><li><strong>Integrated Quality Gate</strong>: Changes must pass a rigorous verification pipeline combining Lint, Vitest, and Build before release eligibility.</li><li><strong>Documentation Auto-Sync</strong>: Technical specifications and user guides are kept up-to-date in real time.</li></ol><h2 id="🚀-2-solution-engineering-track" tabindex="-1">🚀 2. Solution Engineering Track <a class="header-anchor" href="#🚀-2-solution-engineering-track" aria-label="Permalink to &quot;🚀 2. Solution Engineering Track&quot;">​</a></h2><p>A strategic support pipeline for successfully adopting Mocking GUI in user projects and building a productive mock ecosystem.</p><h3 id="primary-workflow-technical-solution-support" tabindex="-1">Primary Workflow: <code>/technical-solution-support</code> <a class="header-anchor" href="#primary-workflow-technical-solution-support" aria-label="Permalink to &quot;Primary Workflow: `/technical-solution-support`&quot;">​</a></h3><ol><li><strong>Deterministic Project Audit</strong>: Precisely analyzes the target project&#39;s environment (package manager, framework, API scale) to formulate the optimal onboarding strategy.</li><li><strong>Adaptive Infrastructure Setup</strong>: Integrates Service Worker (MSW) and applies browser-level network optimization based on audit results.</li><li><strong>Professional Mock Architecture</strong>: Applies the Handlers / Constants / Factories layer separation principle for a maintainable data environment.</li><li><strong>Skill &amp; Reference Deployment</strong>: Distributes project-specific agent skill sets and technical references to maximize collaboration efficiency.</li></ol><h2 id="🧠-shared-knowledge-base" tabindex="-1">🧠 Shared Knowledge Base <a class="header-anchor" href="#🧠-shared-knowledge-base" aria-label="Permalink to &quot;🧠 Shared Knowledge Base&quot;">​</a></h2><p>Both tracks serve different purposes but share the same level of expertise in <strong>Mocking GUI interfaces and frontend engineering</strong>:</p><ul><li><strong>Service Worker &amp; Browser</strong>: Internals of request interception, caching, and latency simulation in the browser network stack.</li><li><strong>Mocking GUI Core Interface</strong>: Deep understanding of core specs such as <code>HandlerConfigOption</code>, <code>responseVariants</code>, and <code>responseVariantsFn</code>.</li><li><strong>Professional Engineering</strong>: Immutable state management with Immer, deterministic data generation with Faker seed patterns, and relational data integrity.</li></ul>',14)])])}const h=r(t,[["render",o]]);export{u as __pageData,h as default};
